useEffect(() => {
  if (!query) return;
  fetch(`/api/search?q=${encodeURIComponent(query)}`)
    .then(r => {
      if (!r.ok) throw new Error(`Server error (${r.status}) — please try again later.`);
      return r.json();
    })
    .then(setResults)
    .catch(err => setError(err.message));
}, [query]);

useEffect(() => {
  if (!query) return;
  fetch(`/api/search?q=${encodeURIComponent(query)}`)
    .then(async r => {
      try {
        const data = await r.json();
        setResults(data);
      } catch {
        setError("Response was not JSON.");
      }
    });
}, [query]);

useEffect(() => {
  if (!query) return;
  fetch(`/api/search?q=${encodeURIComponent(query)}`)
    .then(r => r.text())
    .then(text => {
      try {
        setResults(JSON.parse(text));
      } catch {
        setError("Not JSON: " + text.slice(0, 80));
      }
    })
    .catch(err => setError(err.message));
}, [query]);
